// Alvea — valutazione soglie cliniche + scrittura InfluxDB (line protocol)
//
// NOTA: il dispositivo ha un solo sensore biomedicale, l'ECG (AD8232).
// Da esso si derivano BPM e, via EDR, la frequenza respiratoria.
//
// Parametri biomedicali valutati (coerenti con backend/app/config.py):
//   - respiration_rate: warning <14/>30, critico <=10/>=40 (allineata
//     all'alert clinico reale del firmware, firmware/alerts.py:
//     check_resp_rate)
//   - bpm:              warning <70/>130, critico <=60/>=150 (puramente
//     informativo: il firmware non genera un alert autonomo su BPM)
//   - skin_temperature: warning <30.5/>35.0, critico <=29.0/>=36.0
//     (temperatura CUTANEA misurata sulla caviglia, non corporea
//     centrale: range coerente col simulatore firmware, ~31-34°C.
//     Puramente informativo: il firmware non genera un alert autonomo
//     su temperatura)

const r = msg.payload;
if (!r || !r.device_id) { node.warn('payload non valido'); return [null, null]; }

// Configurazione InfluxDB letta da variabili d'ambiente del container
const INFLUX_URL = env.get('INFLUX_URL') || 'http://influxdb:8086';
const ORG        = env.get('INFLUX_ORG')    || 'alvea';
const BUCKET     = env.get('INFLUX_BUCKET') || 'vitals';
const TOKEN      = env.get('INFLUX_TOKEN')  || 'alvea-admin-token';

// --- Soglie cliniche (coerenti con config.py del backend FastAPI) ---
const RESP_WARN_LOW=14,  RESP_WARN_HIGH=30,  RESP_CRIT_LOW=10,  RESP_CRIT_HIGH=40;
const BPM_WARN_LOW=70,   BPM_WARN_HIGH=130,  BPM_CRIT_LOW=60,   BPM_CRIT_HIGH=150;
const T_WARN_LOW=30.5,   T_WARN_HIGH=35.0,   T_CRIT_LOW=29.0,   T_CRIT_HIGH=36.0;
const CONTACT_DEBOUNCE = 5; // secondi consecutivi senza contatto prima dell'allarme

const contact = r.sensor_contact;
let alerts = [];

if (!contact) {
    // Regola anti-panico: fascia staccata -> i valori sono 0, non valutare.
    // Emetti allarme tecnico solo dopo CONTACT_DEBOUNCE letture consecutive.
    let lost = (context.get('lost') || 0) + 1;
    context.set('lost', lost);
    if (lost === CONTACT_DEBOUNCE) {
        alerts.push({kind:'contact_lost', severity:'technical',
                     message:'Fascia non a contatto: rilevazione sospesa'});
    }
} else {
    context.set('lost', 0);

    // --- Frequenza respiratoria (parametro chiave per asma) ---
    const resp = r.respiration_rate || 0;
    if (resp > 0) {
        if      (resp <= RESP_CRIT_LOW)  alerts.push({kind:'resp_low',  severity:'critical', message:'Apnea/bradipnea critica: '+resp+' atti/min', value:resp});
        else if (resp >= RESP_CRIT_HIGH) alerts.push({kind:'resp_high', severity:'critical', message:'Tachipnea critica: '+resp+' atti/min', value:resp});
        else if (resp <  RESP_WARN_LOW)  alerts.push({kind:'resp_low',  severity:'warning',  message:'Frequenza respiratoria bassa: '+resp+' atti/min', value:resp});
        else if (resp >  RESP_WARN_HIGH) alerts.push({kind:'resp_high', severity:'warning',  message:'Frequenza respiratoria alta: '+resp+' atti/min', value:resp});
    }

    // --- Frequenza cardiaca ---
    const bpm = r.bpm || 0;
    if (bpm > 0) {
        if      (bpm <= BPM_CRIT_LOW)  alerts.push({kind:'bpm_low',  severity:'critical', message:'Bradicardia critica: '+bpm+' BPM', value:bpm});
        else if (bpm >= BPM_CRIT_HIGH) alerts.push({kind:'bpm_high', severity:'critical', message:'Tachicardia critica: '+bpm+' BPM', value:bpm});
        else if (bpm <  BPM_WARN_LOW)  alerts.push({kind:'bpm_low',  severity:'warning',  message:'BPM sotto soglia: '+bpm, value:bpm});
        else if (bpm >  BPM_WARN_HIGH) alerts.push({kind:'bpm_high', severity:'warning',  message:'BPM sopra soglia: '+bpm, value:bpm});
    }

    // --- Temperatura cutanea (caviglia, non temperatura corporea centrale) ---
    const t = r.skin_temperature || 0;
    if (t > 0) {
        if      (t <= T_CRIT_LOW)  alerts.push({kind:'temp_low',  severity:'critical', message:'Temperatura cutanea molto bassa: '+t+' C', value:t});
        else if (t >= T_CRIT_HIGH) alerts.push({kind:'temp_high', severity:'critical', message:'Temperatura cutanea molto alta: '+t+' C', value:t});
        else if (t <  T_WARN_LOW)  alerts.push({kind:'temp_low',  severity:'warning',  message:'Temperatura cutanea bassa: '+t+' C', value:t});
        else if (t >  T_WARN_HIGH) alerts.push({kind:'temp_high', severity:'warning',  message:'Temperatura cutanea alta: '+t+' C', value:t});
    }
}

// --- InfluxDB Line Protocol (measurement = vitals) ---
// Formato: measurement,tag=val field1=val1,field2=val2
// I tag sono indicizzati (usati per filtrare in Grafana).
// I field sono i valori numerici delle serie temporali.
const contactInt = contact ? 1 : 0;
const tags   = 'device_id=' + r.device_id +
               ',source='   + (r.source || 'unknown') +
               (r.patient_id ? ',patient_id=' + r.patient_id : '');
const fields = 'bpm='              + (r.bpm || 0) +
               ',skin_temperature=' + (r.skin_temperature || 0) +
               ',respiration_rate=' + (r.respiration_rate || 0) +
               ',sensor_contact='   + contactInt + 'i' +
               ',alert_count='      + alerts.length + 'i' +
               (r.battery_pct != null ? ',battery_pct=' + r.battery_pct : '');
const line = 'vitals,' + tags + ' ' + fields;

// Messaggio per il nodo http request -> InfluxDB
const influxMsg = {
    method: 'POST',
    url: INFLUX_URL + '/api/v2/write?org=' + ORG + '&bucket=' + BUCKET + '&precision=s',
    headers: {
        'Authorization': 'Token ' + TOKEN,
        'Content-Type': 'text/plain; charset=utf-8'
    },
    payload: line
};

// Messaggio per il nodo mqtt out -> topic alerts (solo se ci sono alert)
let alertMsg = null;
if (alerts.length > 0) {
    node.status({fill:'red', shape:'dot', text: alerts[0].severity+': '+alerts[0].kind});
    // Il topic viene costruito con il device_id reale
    alertMsg = {
        topic: 'alvea/devices/' + r.device_id + '/alerts',
        payload: JSON.stringify({
            device_id: r.device_id,
            patient_id: r.patient_id || null,
            ts: Date.now(),
            alerts: alerts
        })
    };
} else {
    node.status({fill:'green', shape:'dot', text:'ok'});
}

// Output 1 -> InfluxDB, Output 2 -> MQTT alert
return [influxMsg, alertMsg];
